using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "your-api-key-here";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var topic = args.Length > 0 ? string.Join(' ', args) : "recent breakthroughs in quantum computing";

Console.WriteLine($"🔍 Research Agent — topic: \"{topic}\"\n");

// --- Tools ---
var notebook = new Notebook();
var webSearch = new WebSearchService();

var chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.Search),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research assistant. Your job is to research a topic thoroughly and
        produce a well-organized summary.

        Follow this workflow:
        1. Search the web for information on the topic (make 2-3 searches with
           different queries to get broad coverage).
        2. As you find important facts, save them as notes with clear source attribution.
        3. After gathering enough information, review your notes, then produce a final
           summary organized with clear headings and bullet points.

        Always cite your sources. Be thorough but concise.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
];

// --- Agent loop ---
var done = false;
while (!done)
{
    var response = await chatClient.GetResponseAsync(messages, chatOptions);

    // Append all response messages to history
    foreach (var msg in response.Messages)
        messages.Add(msg);

    // Check whether the model invoked any tools this turn
    bool calledTools = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    if (!calledTools)
    {
        // Final assistant reply — print and exit
        var finalText = response.Messages
            .Where(m => m.Role == ChatRole.Assistant)
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .LastOrDefault()?.Text;

        Console.WriteLine("═══════════════════════════════════════");
        Console.WriteLine("📝 RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════\n");
        Console.WriteLine(finalText);

        if (notebook.Notes.Count > 0)
        {
            Console.WriteLine("\n───────────────────────────────────────");
            Console.WriteLine($"📌 {notebook.Notes.Count} note(s) saved during research.");
        }

        done = true;
    }
}

// ──────────────────────────────────────────────
// Tool implementations
// ──────────────────────────────────────────────

/// <summary>Simulated web search that returns placeholder results.
/// Swap the body of Search() with a real API (Bing, Google, Brave) for production use.</summary>
public sealed class WebSearchService
{
    private static readonly JsonSerializerOptions s_json = new() { WriteIndented = true };

    [Description("Search the web for information. Returns a list of result snippets with titles and URLs.")]
    public string Search([Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        // Simulated results — replace with a real search API call.
        var results = new[]
        {
            new
            {
                Title = $"Overview of {query}",
                Url = $"https://example.com/search?q={Uri.EscapeDataString(query)}&result=1",
                Snippet = $"A comprehensive overview covering the latest developments in {query}. "
                         + "Researchers have made significant progress in this area over the past year."
            },
            new
            {
                Title = $"Recent advances in {query}",
                Url = $"https://example.com/search?q={Uri.EscapeDataString(query)}&result=2",
                Snippet = $"New studies reveal exciting breakthroughs related to {query}, "
                         + "with potential applications across multiple industries."
