/// <summary>A simple in-memory notebook the agent uses to collect and review findings.</summary>
public sealed class Notebook
{
    public List<NoteEntry> Notes { get; } = [];

    [Description("Save a research note. Use this to record important facts and their sources.")]
    public string AddNote(
        [Description("The content of the note")] string content,
        [Description("The source URL or reference")] string source)
    {
        Notes.Add(new NoteEntry(content, source, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note #{Notes.Count} saved");
        return $"Note #{Notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        return JsonSerializer.Serialize(
            Notes.Select((n, i) => new { Index = i + 1, n.Content, n.Source }),
            new JsonSerializerOptions { WriteIndented = true });
    }
}

public record NoteEntry(string Content, string Source, DateTime Timestamp);

